import{_ as e,a as r,b as t,c as n}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as d,o as i,c as l,a2 as u}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Yedek Kopya ve Okuma Kaynağı Değiştirme","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Other/redundant-backup-and-read-source.md","filePath":"tr-TR/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),s={name:"tr-TR/Other/redundant-backup-and-read-source.md"};function o(k,a,c,p,y,h){return i(),l("div",null,[...a[0]||(a[0]=[u('<h1 id="yedek-kopya-ve-okuma-kaynagı-degistirme" tabindex="-1">Yedek Kopya ve Okuma Kaynağı Değiştirme <a class="header-anchor" href="#yedek-kopya-ve-okuma-kaynagı-degistirme" aria-label="Permalink to &quot;Yedek Kopya ve Okuma Kaynağı Değiştirme&quot;">​</a></h1><p>Redundant backup, zaten yüklenmiş bir dosyanın ek kopyasını saklar.</p><p>Hem birincil dosya hem yedek dosya read sources olarak kullanılabilir. Ziyaretçiler genellikle bir fark görmez. Tek fark dosyanın hangi depolama kanalından sunulduğudur.</p><h2 id="redundant-backup-neler-yapabilir" tabindex="-1">Redundant Backup Neler Yapabilir? <a class="header-anchor" href="#redundant-backup-neler-yapabilir" aria-label="Permalink to &quot;Redundant Backup Neler Yapabilir?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Özellik</th><th>Açıklama</th></tr></thead><tbody><tr><td>Ek kopya saklama</td><td>Tek bir kanal arızası riskini azaltmak için dosyaları başka bir upload channel içine yedekler.</td></tr><tr><td>Read source değiştirme</td><td>Backup başarılı olduktan sonra dosya okumayı primary channel ve backup channel arasında değiştirir.</td></tr><tr><td>Single-file backup</td><td>Dosya ayrıntı sayfasından tek dosyayı yedekler.</td></tr><tr><td>Batch backup</td><td>Yönetim sayfasında birden fazla dosya seçip birlikte yedekler.</td></tr><tr><td>Global redundant backup</td><td>Other Settings içinden klasöre göre dosya yedekler.</td></tr></tbody></table><h2 id="redundant-backup-girisi" tabindex="-1">Redundant Backup Girişi <a class="header-anchor" href="#redundant-backup-girisi" aria-label="Permalink to &quot;Redundant Backup Girişi&quot;">​</a></h2><p>Şurayı açın:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Redundant backup" loading="lazy"></p><p>Bu giriş, bir klasöre veya tüm dosyalara toplu yedek eklemek için uygundur.</p><p>Backup channel elle seçilebilir veya automatic switching seçilip ImgBed&#39;in uygun yedek kanalı bulması sağlanabilir.</p><h2 id="dosya-ayrıntısından-backup" tabindex="-1">Dosya Ayrıntısından Backup <a class="header-anchor" href="#dosya-ayrıntısından-backup" aria-label="Permalink to &quot;Dosya Ayrıntısından Backup&quot;">​</a></h2><p>Yönetim panelinde dosya ayrıntı sayfasını açın ve backup düğmesine tıklayın.</p><p><img src="'+r+'" alt="Dosya ayrıntısında backup" loading="lazy"></p><p>Bu, önemli tek bir dosyayı gerektiğinde yedeklemek için uygundur.</p><p>Backup başarılı olduktan sonra dosya ayrıntı sayfası kullanılabilir read sources değerlerini gösterir.</p><h2 id="secime-gore-batch-backup" tabindex="-1">Seçime Göre Batch Backup <a class="header-anchor" href="#secime-gore-batch-backup" aria-label="Permalink to &quot;Seçime Göre Batch Backup&quot;">​</a></h2><p>Yönetim panelinde birden fazla dosya seçin ve batch backup çalıştırın.</p><p><img src="'+t+'" alt="Batch backup" loading="lazy"></p><p>Bu, bir dosya grubunu işlemek için uygundur.</p><p>Selection backup, file details backup ve Other Settings altındaki redundant backup aynı backup system&#39;i kullanır. Sadece farklı giriş noktalarıdır.</p><h2 id="backup-sonrası-read-source-degistirme" tabindex="-1">Backup Sonrası Read Source Değiştirme <a class="header-anchor" href="#backup-sonrası-read-source-degistirme" aria-label="Permalink to &quot;Backup Sonrası Read Source Değiştirme&quot;">​</a></h2><p>Backup tamamlandıktan sonra dosya ayrıntı sayfası read source değiştirmenize izin verir:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Açıklama</th></tr></thead><tbody><tr><td>Primary channel</td><td>Özgün upload channel üzerinden okur.</td></tr><tr><td>Backup channel</td><td>Backup channel üzerinden okur.</td></tr></tbody></table><p><img src="'+n+'" alt="Backup sonrası read source değiştirme" loading="lazy"></p><p>Ziyaretçilerin dosyanın primary mi backup channel üzerinden mi sunulduğunu bilmesi gerekmez.</p><p>Seçtiğiniz read source sonraki dosya erişimleri için tercih edilen kaynak olur.</p><h2 id="backup-ne-zaman-atlanır" tabindex="-1">Backup Ne Zaman Atlanır? <a class="header-anchor" href="#backup-ne-zaman-atlanır" aria-label="Permalink to &quot;Backup Ne Zaman Atlanır?&quot;">​</a></h2><p>Backup sırasında şu durumlar atlanır. Bunlar hata değildir.</p><table tabindex="0"><thead><tr><th>Durum</th><th>Neden Atlanır</th></tr></thead><tbody><tr><td>Already backed up</td><td>Zaten backup bulunan dosya tekrar yedeklenmez.</td></tr><tr><td>Primary and backup channels are the same</td><td>Backup anlamlı olması için başka bir kanalda saklanmalıdır.</td></tr><tr><td>No usable backup channel</td><td>Uygun alternatif kanal yoktur.</td></tr></tbody></table><p>Kısaca: backup başka bir kanala gitmelidir ve zaten yedeklenmiş dosyalar tekrar alan tüketmez.</p><h2 id="primary-channel-ve-backup-channel" tabindex="-1">Primary Channel ve Backup Channel <a class="header-anchor" href="#primary-channel-ve-backup-channel" aria-label="Permalink to &quot;Primary Channel ve Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ad</th><th>Anlamı</th></tr></thead><tbody><tr><td>Primary channel</td><td>Dosya ilk yüklendiğinde kullanılan kanal.</td></tr><tr><td>Backup channel</td><td>Redundant copy saklayan kanal.</td></tr><tr><td>Primary read source</td><td>Dosya şu anda primary channel üzerinden okunuyor.</td></tr><tr><td>Backup read source</td><td>Dosya şu anda backup channel üzerinden okunuyor.</td></tr></tbody></table><p>Primary ve backup read sources kullanıcı açısından aynı davranır.</p><p>Backup file kullanılabilir olduğu sürece görseller, videolar ve download links backup read source&#39;a geçtikten sonra çalışmaya devam eder.</p><h2 id="dosya-silindiginde-ne-olur" tabindex="-1">Dosya Silindiğinde Ne Olur? <a class="header-anchor" href="#dosya-silindiginde-ne-olur" aria-label="Permalink to &quot;Dosya Silindiğinde Ne Olur?&quot;">​</a></h2><p>Bir dosya silindiğinde ImgBed hem primary file hem backup file değerini siler.</p>',37)])])}const B=d(s,[["render",o]]);export{g as __pageData,B as default};
